import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import 'react-lazy-load-image-component/src/effects/blur.css';
import { Lock, Truck } from 'lucide-react';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import { productImageUrl } from '../lib/productImage';
import LoadingSpinner from '../components/LoadingSpinner';

const Cart = () => {
  const navigate = useNavigate();
  const {
    cart,
    cartState,
    loading: cartLoading,
    updateCartItem,
    removeFromCart,
    clearCart,
    applyCoupon,
    removeCoupon,
    getSubtotal
  } = useCart();
  const [couponCode, setCouponCode] = useState('');

  const totals = cartState.totals;

  const handleApplyCoupon = async () => {
    const code = couponCode.trim();
    if (!code) {
      toast.error('Enter a coupon code');
      return;
    }
    await applyCoupon(code);
  };

  const handleCheckout = () => {
    if (!cart.length) {
      toast.error('Your cart is empty');
      return;
    }
    navigate('/checkout');
  };

  const bumpQty = (line, delta) => {
    const p = line.product || {};
    const ref = p._id || line.product;
    const stockRaw = p.stock ?? p.stockQuantity;
    const stock =
      stockRaw != null && Number.isFinite(Number(stockRaw)) ? Math.floor(Number(stockRaw)) : null;
    const next = line.quantity + delta;
    if (next < 1) return;
    if (stock != null && next > stock) {
      toast.error(`Only ${stock} in stock for ${p.name || 'this item'}`);
      return;
    }
    updateCartItem(ref, next);
  };

  return (
    <>
      <Helmet>
        <title>Cart | Nova Shop</title>
        <meta
          name="description"
          content="Review your Nova Shop basket, apply a coupon, and proceed to secure checkout."
        />
        <meta property="og:title" content="Cart | Nova Shop" />
      </Helmet>
      <header className="page-header">
        <div className="container">
          <h1 className="page-header__title">Shopping cart</h1>
          <p className="page-header__subtitle">Review items, apply savings, then checkout securely.</p>
          <ol className="breadcrumb" aria-label="Breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/shop">Shop</Link>
            </li>
            <li className="active" aria-current="page">
              Cart
            </li>
          </ol>
        </div>
      </header>

      <main className="cart-page" id="main-content">
        <div className="container">
          <div className="cart-layout">
            <div className="cart-page__main">
              <div className="cart-page__head">
                <h2 className="cart-page__title">Your items</h2>
                {cart.length > 0 && (
                  <button type="button" className="cart-page__clear" onClick={() => clearCart()}>
                    Clear cart
                  </button>
                )}
              </div>

              <div className="cart-items">
                {cartLoading ? (
                  <div className="cart-loading">
                    <LoadingSpinner size="lg" label="Loading cart" />
                    <p className="cart-loading__note">Loading your cart…</p>
                  </div>
                ) : cart.length === 0 ? (
                  <div className="empty-cart animate-in">
                    <div className="empty-icon" aria-hidden>
                      🛒
                    </div>
                    <h3>Your cart is empty</h3>
                    <p className="empty-cart__lead">Browse the shop to add products you love.</p>
                    <Link to="/shop" className="btn btn-primary">
                      Start shopping
                    </Link>
                  </div>
                ) : (
                  cart.map((line, idx) => {
                    const p = line.product || {};
                    const ref = p._id || line.product;
                    const img = productImageUrl(p);
                    const stockRaw = p.stock ?? p.stockQuantity;
                    const stock =
                      stockRaw != null && Number.isFinite(Number(stockRaw))
                        ? Math.floor(Number(stockRaw))
                        : null;
                    const atMax = stock != null && line.quantity >= stock;
                    return (
                      <div
                        key={String(ref)}
                        className="cart-item"
                        style={{ animationDelay: `${idx * 0.08}s` }}
                      >
                        <div className="cart-item-img">
                          {img ? (
                            <LazyLoadImage
                              src={img}
                              alt={p.name || ''}
                              className="cart-item-img__photo"
                              effect="blur"
                            />
                          ) : (
                            <span className="cart-item-img__emoji" aria-hidden>
                              📦
                            </span>
                          )}
                        </div>
                        <div className="cart-item-info">
                          <Link to={`/shop/${p.slug || ''}`} className="cart-item-name-link">
                            <div className="cart-item-name">{p.name}</div>
                          </Link>
                          <div className="qty-control">
                            <button type="button" className="qty-btn" onClick={() => bumpQty(line, -1)}>
                              −
                            </button>
                            <span className="qty-display">{line.quantity}</span>
                            <button
                              type="button"
                              className="qty-btn"
                              onClick={() => bumpQty(line, 1)}
                              disabled={atMax}
                              aria-label={atMax ? 'Maximum stock reached' : 'Increase quantity'}
                            >
                              +
                            </button>
                          </div>
                          {stock != null ? (
                            <span className="cart-item__stock-hint">{stock} in stock</span>
                          ) : null}
                        </div>
                        <div className="cart-item-price">
                          <div className="cart-item-total">
                            £{Number(line.lineTotal ?? line.price * line.quantity).toFixed(2)}
                          </div>
                          <div className="cart-item__unit">£{Number(line.price).toFixed(2)} each</div>
                          <button type="button" className="cart-item-remove" onClick={() => removeFromCart(ref)}>
                            ✕ Remove
                          </button>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>

            <aside className="cart-page__summary-wrap">
              <div className="cart-summary">
                <h3>Order summary</h3>

                <div className="coupon-group">
                  <input
                    type="text"
                    placeholder="COUPON CODE"
                    value={couponCode}
                    onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                    maxLength={32}
                    aria-label="Coupon code"
                  />
                  <button type="button" className="btn btn-gold btn-sm" onClick={handleApplyCoupon}>
                    Apply
                  </button>
                </div>
                {cartState.coupon && (
                  <p className="coupon-applied">
                    {cartState.coupon.code} applied
                    <button type="button" className="link-btn" onClick={() => removeCoupon()}>
                      Remove
                    </button>
                  </p>
                )}

                <div className="summary-row">
                  <span className="label">Subtotal</span>
                  <span className="value">£{getSubtotal().toFixed(2)}</span>
                </div>
                {totals && (
                  <>
                    <div className="summary-row">
                      <span className="label">Discount</span>
                      <span className="value summary-row__discount">
                        −£{Number(totals.discountAmount || 0).toFixed(2)}
                      </span>
                    </div>
                    <div className="summary-row total">
                      <span className="label">Total</span>
                      <span className="value">£{Number(totals.total || 0).toFixed(2)}</span>
                    </div>
                  </>
                )}

                <button
                  type="button"
                  className="btn btn-gold btn-full cart-summary__checkout"
                  onClick={handleCheckout}
                  disabled={!cart.length}
                >
                  Proceed to checkout →
                </button>

                <ul className="cart-trust-list" aria-label="Checkout benefits">
                  <li>
                    <Lock size={16} strokeWidth={1.75} aria-hidden />
                    Secure SSL checkout
                  </li>
                  <li>
                    <Truck size={16} strokeWidth={1.75} aria-hidden />
                    Fast dispatch on in-stock items
                  </li>
                </ul>
                <p className="cart-summary__hint">
                  Delivery speed is selected at checkout. Prices include VAT where applicable.
                </p>
              </div>
            </aside>
          </div>
        </div>
      </main>
    </>
  );
};

export default Cart;
